const express = require('express');
const Redis = require('ioredis');
const twilio = require('twilio');

const {
  PORT = 3000,
  REDIS_URL = 'redis://127.0.0.1:6379',
  TWILIO_ACCOUNT_SID,
  TWILIO_AUTH_TOKEN,
  TWILIO_FROM_NUMBER
} = process.env;

if (!TWILIO_ACCOUNT_SID || !TWILIO_AUTH_TOKEN || !TWILIO_FROM_NUMBER) {
  throw new Error('Missing Twilio env vars: TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN, TWILIO_FROM_NUMBER');
}

const redis = new Redis(REDIS_URL);
const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

const app = express();
app.use(express.json());

const CODE_TTL_SECONDS = 10 * 60;
const MAX_ATTEMPTS = 10;

function codeKey(userId) {
  return `2fa:code:${userId}`;
}
function attemptsKey(userId) {
  return `2fa:attempts:${userId}`;
}

function generate6DigitCode() {
  return String(Math.floor(100000 + Math.random() * 900000));
}

async function sendSms(to, body) {
  return twilioClient.messages.create({
    to,
    from: TWILIO_FROM_NUMBER,
    body
  });
}

app.post('/2fa/request', async (req, res) => {
  try {
    const { userId, phoneNumber } = req.body || {};
    if (!userId || !phoneNumber) {
      return res.status(400).json({ error: 'userId and phoneNumber are required' });
    }

    const code = generate6DigitCode();

    const multi = redis.multi();
    multi.set(codeKey(userId), code, 'EX', CODE_TTL_SECONDS);
    multi.set(attemptsKey(userId), '0', 'EX', CODE_TTL_SECONDS);
    await multi.exec();

    await sendSms(phoneNumber, `Your verification code is: ${code}. It expires in 10 minutes.`);

    return res.json({ ok: true, expiresInSeconds: CODE_TTL_SECONDS });
  } catch (err) {
    return res.status(500).json({ error: 'failed_to_send_code' });
  }
});

app.post('/2fa/verify', async (req, res) => {
  try {
    const { userId, code } = req.body || {};
    if (!userId || !code) {
      return res.status(400).json({ error: 'userId and code are required' });
    }

    const storedCode = await redis.get(codeKey(userId));
    if (!storedCode) {
      return res.status(400).json({ error: 'code_expired_or_not_requested' });
    }

    const attempts = await redis.incr(attemptsKey(userId));
    const ttl = await redis.ttl(attemptsKey(userId));
    if (ttl > 0) {
      await redis.expire(attemptsKey(userId), ttl);
    } else {
      await redis.expire(attemptsKey(userId), CODE_TTL_SECONDS);
    }

    if (attempts > MAX_ATTEMPTS) {
      await redis.del(codeKey(userId));
      await redis.del(attemptsKey(userId));
      return res.status(429).json({ error: 'locked_out_too_many_attempts' });
    }

    if (String(code).trim() !== storedCode) {
      return res.status(401).json({
        error: 'invalid_code',
        attemptsRemaining: Math.max(0, MAX_ATTEMPTS - attempts)
      });
    }

    await redis.del(codeKey(userId));
    await redis.del(attemptsKey(userId));

    return res.json({ ok: true, accessGranted: true });
  } catch (err) {
    return res.status(500).json({ error: 'verification_failed' });
  }
});

